% plot_cubesat_results.m
% Plots the data generated by Cubesat_Full_Control.slx

% Ensure data exists
if ~exist('simOut','var')
    error('No simulation data found (simOut variable missing).');
end

% Extract Data Arrays
t       = simOut.tout;
theta   = simOut.theta_out(1:length(t), 1);
omega   = simOut.omega_out(1:length(t), 1);
omega_w = simOut.omega_w_out(1:length(t), 1);
tau     = simOut.tau_out(1:length(t), 1);

% Convert units for display
theta_deg = rad2deg(theta);
omega_deg = rad2deg(omega);
theta_ref_deg = rad2deg(theta_ref);
omega_th_high_deg = rad2deg(omega_th_high);
omega_th_low_deg = rad2deg(omega_th_low);

% Find switching index by finding where pointing started permanently
% or just the first time we fell below the lower threshold
idx_switch = find(abs(omega) <= omega_th_low, 1, 'first');
if isempty(idx_switch)
    t_switch = NaN;
else
    t_switch = t(idx_switch);
end

%% Plot Design Properties
turquoise      = [0.00 0.80 0.80];
midnightpurple = [0.50 0.40 0.85];
darkyellow     = [0.90 0.75 0.20];
pastelgreen    = [0.55 0.85 0.60];
lightred       = [0.95 0.35 0.35];

figure('Color','k', ...
       'Name','Full Control Sequence (Detumbling -> Pointing)', ...
       'Position',[100 50 1100 900]);

% 1. Attitude Angle (Theta)
ax1 = subplot(4,1,1);
plot(t, theta_deg, 'LineWidth', 2, 'Color', turquoise); hold on;
yline(theta_ref_deg, '--w', 'LineWidth', 1.5, 'Label', 'Target Angle');
if ~isnan(t_switch), xline(t_switch, '--', 'Color', lightred, 'LineWidth', 1.5); end
ylabel('\theta [deg]', 'Color', 'w');
title('Attitude Angle (Pointing)', 'Color', 'w');
grid on;

% 2. Body Angular Rate (Omega)
ax2 = subplot(4,1,2);
plot(t, omega_deg, 'LineWidth', 2, 'Color', midnightpurple); hold on;
yline(omega_th_low_deg, '--', 'Color', [0.7 0.7 0.7], 'LineWidth', 1.2);
yline(-omega_th_low_deg, '--', 'Color', [0.7 0.7 0.7], 'LineWidth', 1.2);
if ~isnan(t_switch), xline(t_switch, '--', 'Color', lightred, 'LineWidth', 1.5); end
ylabel('\omega [deg/s]', 'Color', 'w');
title('Satellite Angular Velocity (Detumbling)', 'Color', 'w');
grid on;

% 3. Control Torque (Tau)
ax3 = subplot(4,1,3);
plot(t, tau, 'LineWidth', 2, 'Color', darkyellow); hold on;
if ~isnan(t_switch), xline(t_switch, '--', 'Color', lightred, 'LineWidth', 1.5); end
if exist('tau_max', 'var'), ylim([-tau_max*1.5, tau_max*1.5]); end
ylabel('\tau [Nm]', 'Color', 'w');
title('Reaction Wheel Motor Torque', 'Color', 'w');
grid on;

% 4. Wheel Speed (Omega_w)
ax4 = subplot(4,1,4);
plot(t, omega_w, 'LineWidth', 2, 'Color', pastelgreen); hold on;
if ~isnan(t_switch), xline(t_switch, '--', 'Color', lightred, 'LineWidth', 1.5); end
ylabel('\omega_w [rad/s]', 'Color', 'w');
xlabel('Time [s]', 'Color', 'w');
title('Reaction Wheel Speed', 'Color', 'w');
grid on;

% Formatting axes
for ax = [ax1 ax2 ax3 ax4]
    set(ax, 'Color', 'k', 'XColor', 'w', 'YColor', 'w', 'GridColor', [0.5 0.5 0.5]);
end

% Region Labels
if ~isnan(t_switch)
    text(ax1, t_switch/2, max(ylim(ax1))*0.8, 'DETUMBLING', 'Color','w', 'FontWeight','bold', 'HorizontalAlignment','center');
    text(ax1, (t_switch + t_stop)/2, max(ylim(ax1))*0.8, 'POINTING', 'Color','w', 'FontWeight','bold', 'HorizontalAlignment','center');
end
